files.content:
.banner-surface {
  position: relative;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  border-radius: var(--dimension-radius-075);
}

.banner-header-surface {
  width: 100%;
  height: var(--dimension-space-100);
  flex-shrink: 0;
  overflow: hidden;
  border-bottom: var(--dimension-stroke-width-015) solid var(--color-border-primary);
}

.banner-header {
  width: 100%;
  height: 100%;
  background: repeating-linear-gradient(
    -45deg,
    var(--banner-content),
    var(--banner-content) var(--dimension-size-100),
    transparent var(--dimension-size-100),
    transparent var(--dimension-size-200)
  );
}

.banner-body {
  padding: var(--dimension-space-075);
  min-height: var(--dimension-size-400);
  display: flex;
  align-items: flex-start;
  gap: var(--dimension-space-075);
}

.banner-message {
  color: var(--banner-content);
  flex: 1;
  min-width: 0;
}

.banner-dismiss {
  background: none;
  border: none;
  margin: 0;
  padding: var(--dimension-space-025);
  color: var(--banner-content);
  cursor: pointer;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  border-radius: var(--dimension-radius-050);
  position: relative;
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
}

.banner-dismiss::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;
  background-color: transparent;
  transition: var(--effect-transition-interaction-background-short-2, background-color var(--effect-motion-short-2));
  pointer-events: none;
}

.banner-dismiss:hover::before  { background-color: var(--color-interaction-hover); }
.banner-dismiss:active::before { background-color: var(--color-interaction-pressed); }

.banner-dismiss:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-interaction-focus);
  outline-offset: var(--dimension-stroke-width-015);
}

/* ─── Floating ──────────────────────────────────────────────────────────────── */

.floating-position {
  position: fixed;
  top: var(--dimension-space-200);
  left: 50%;
  transform: translateX(-50%);
  pointer-events: none;
}

.floating-toast {
  pointer-events: auto;
  animation: bannerFadeIn var(--effect-motion-short-2, 150ms) forwards;
}

.floating-toast--closing {
  animation: bannerFadeOut var(--effect-motion-short-3, 200ms) forwards;
}

@keyframes bannerFadeIn {
  from { opacity: 0; transform: translateY(-8px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes bannerFadeOut {
  from { opacity: 1; transform: translateY(0); }
  to   { opacity: 0; transform: translateY(-4px); }
}

import { Component, Prop, State, Event, EventEmitter, Watch, h, Host } from '@stencil/core';
import { resolveCssTimeMs, TOKEN_DEFAULTS } from '../../utils';

export type BannerIntent =
  | 'brand' | 'positive' | 'negative' | 'warning' | 'caution'
  | 'ai' | 'neutral' | 'walkthrough' | 'guide';

export type BannerContrast = 'faint' | 'medium' | 'bold' | 'strong';

@Component({
  tag: 'ds-banner',
  styleUrl: 'Banner.css',
  scoped: true,
})
export class Banner {
  @Prop() intent: BannerIntent = 'neutral';
  @Prop() contrast: BannerContrast = 'medium';
  @Prop() message: string = '';
  /** Renders the diagonal-stripe accent bar above the body. */
  @Prop() header: boolean = false;
  /** Renders at a fixed position (centered top) and auto-dismisses after 4 s. */
  @Prop() floating: boolean = false;
  @Prop() showDismiss: boolean = false;
  @Prop() dismissLabel: string = 'Dismiss';

  @State() private closing: boolean = false;

  @Event() dsDismiss!: EventEmitter<void>;

  private dismissTimer: ReturnType<typeof setTimeout> | null = null;
  private closeTimer: ReturnType<typeof setTimeout> | null = null;

  private get fadeOutMs(): number {
    return resolveCssTimeMs(TOKEN_DEFAULTS.motionShort3, TOKEN_DEFAULTS.animationDurationShort3);
  }

  private get autoDismissMs(): number {
    return resolveCssTimeMs(TOKEN_DEFAULTS.animationDelayLong2, TOKEN_DEFAULTS.animationDelayLong2);
  }

  componentDidLoad() {
    if (this.floating && this.message) this.scheduleDismiss();
  }

  @Watch('message')
  onMessageChange(newVal: string) {
    if (this.floating && newVal) {
      this.closing = false;
      this.scheduleDismiss();
    }
  }

  disconnectedCallback() {
    this.clearTimers();
  }

  private clearTimers() {
    if (this.dismissTimer) { clearTimeout(this.dismissTimer); this.dismissTimer = null; }
    if (this.closeTimer)   { clearTimeout(this.closeTimer);   this.closeTimer = null; }
  }

  private scheduleDismiss() {
    this.clearTimers();
    this.dismissTimer = setTimeout(() => {
      this.dismissTimer = null;
      this.beginClose();
    }, this.autoDismissMs);
  }

  private beginClose() {
    this.clearTimers();
    if (this.floating) {
      this.closing = true;
      this.closeTimer = setTimeout(() => {
        this.closing = false;
        this.closeTimer = null;
        this.dsDismiss.emit();
      }, this.fadeOutMs);
    } else {
      this.dsDismiss.emit();
    }
  }

  private getContentColor(): string {
    if (this.contrast === 'bold') return 'var(--color-foreground-on-bold-background-primary)';
    const c = this.contrast === 'faint' ? 'bold' : this.contrast === 'medium' ? 'strong' : 'medium';
    return `var(--color-foreground-${c}-${this.intent})`;
  }

  private getBg(): string {
    return `var(--color-background-${this.contrast}-${this.intent})`;
  }

  private getElevation(): string {
    return this.floating
      ? 'var(--effect-elevation-elevated-floating)'
      : 'var(--effect-elevation-elevated-sm)';
  }

  render() {
    const contentColor = this.getContentColor();
    const isAssertive = this.intent === 'negative';

    const bannerEl = (
      <div
        class={{ 'banner-wrapper': true }}
        style={{ '--banner-content': contentColor } as { [key: string]: string }}
        role={isAssertive ? 'alert' : 'status'}
        aria-live={isAssertive ? undefined : 'polite'}
      >
        <div
          class="banner-surface"
          style={{
            backgroundColor: this.getBg(),
            boxShadow: this.getElevation(),
          }}
        >
          {this.header && (
            <div class="banner-header-surface">
              <div class="banner-header" />
            </div>
          )}
          <div class="banner-body">
            <ds-text class="banner-message" as="div" variant="text-body-medium" color="inherit">
              {this.message}
            </ds-text>
            {this.showDismiss && (
              <button
                type="button"
                class="banner-dismiss"
                onClick={() => this.beginClose()}
                aria-label={this.dismissLabel}
              >
                &times;
              </button>
            )}
          </div>
        </div>
      </div>
    );

    if (this.floating) {
      return (
        <Host style={{ display: 'contents' }}>
          <div class="floating-position" style={{ zIndex: '9998' }}>
            <div class={{ 'floating-toast': true, 'floating-toast--closing': this.closing }}>
              {bannerEl}
            </div>
          </div>
        </Host>
      );
    }

    return <Host style={{ display: 'contents' }}>{bannerEl}</Host>;
  }
}
